/**
 * TypeScript mirrors of all C# backend enums.
 *
 * Pattern: `const` object + derived union type.
 * - Runtime value: `WorkScheduleStatus.Approved` === "Approved"
 * - Type safety:   `status: WorkScheduleStatus` only accepts known values
 * - Comparisons:   `schedule.status === WorkScheduleStatus.Approved`
 */

// ── Work Schedule ─────────────────────────────────────────────────────────────

export const WorkScheduleStatus = {
  Draft:     "Draft",
  Submitted: "Submitted",
  Approved:  "Approved",
  Rejected:  "Rejected",
} as const;
export type WorkScheduleStatus = typeof WorkScheduleStatus[keyof typeof WorkScheduleStatus];

